"const fs = require('fs');
const readline = require('readline');

const logPath = 'C:/Users/paloptical/.gemini/antigravity/brain/f89774ed-f905-432d-8902-e9fb55f69e45/.system_generated/logs/transcript.jsonl';

const rl = readline.createInterface({
  input: fs.createReadStream(logPath),
  crlfDelay: Infinity
});

let lineCount = 0;

rl.on('line', (line) => {
  lineCount++;
  if (line.includes('FORM_CLASSES') && line.includes('menuCategories') && line.includes('App: React.FC')) {
    try {
      const data = JSON.parse(line);
      let content = '';
      if (data.content) {
        content = data.content;
      } else if (data.tool_calls) {
        // Look inside tool call arguments
        for (const call of data.tool_calls) {
          if (call.args && call.args.CodeContent) {
            content = call.args.CodeContent;
          }
        }
      }

      if (content && content.length > 2000) {
        const isTruncated = content.includes('truncated') || content.includes('Showing lines');
        console.log(`Line ${lineCount}: step=${data.step_index}, length=${content.length}, truncated=${isTruncated}`);
        fs.writeFileSync(`app_tsx_raw_${data.step_index || lineCount}.txt`, content);
      }
    } catch (e) {
      // Ignore
    }
  }
});

rl.on('close', () => {
  console.log('Finished search.');
});
"
